  mySqlFlexibleServers(
    where: {
      NOT: {
        OR: [
          { engineVersion_MATCHES: "^5\\.7(\\.|$)" }
          { engineVersion_MATCHES: "^8\\.0(\\.|$)" }
          { engineVersion_MATCHES: "^8\\.4(\\.|$)" }
        ]
      }
    }
  ) {
    ...AssetFragment
    engineVersion
  }
}
